// Filter patients inactive for 30+ days who have not been reactivated.
const items = $input.all();
const tz = $env.TIMEZONE || 'Asia/Kolkata';
const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });
const thresholdDate = new Date();
thresholdDate.setDate(thresholdDate.getDate() - 30);
const filtered = items.filter(item => {
  const p = item.json;
  if (p.status === 'inactive' || p.status === 'completed') return false;
  if (p.reactivation_sent === true) return false;
  if (!p.phone || !/^\+[1-9]\d{6,14}$/.test(p.phone)) return false;
  if (p.last_message_sent && new Date(p.last_message_sent) > thresholdDate) return false;
  return true;
});
if (filtered.length === 0) return [{ json: { _skip: true, reason: 'No inactive patients to reactivate this week' } }];
return filtered.map(item => {
  const p = item.json;
  const name = p.name || 'there';
  const clinic = p.clinic_name || $env.DEFAULT_CLINIC_NAME || 'our clinic';
  const doctor = p.doctor_name || $env.DEFAULT_DOCTOR_NAME || 'your doctor';
  return { json: { ...p, _clinic_id: p.clinic_id, _workflow: 'workflow-5-reactivation', _message_type: 'reactivation', _scheduled_date: todayStr, _to_phone: 'whatsapp:' + p.phone, _name: name, _clinic_name: clinic, _doctor_name: doctor, _content_sid: $env.TWILIO_CONTENT_PATIENT_REMINDER || $env.TWILIO_CONTENT_REACTIVATION || '', _content_variables: JSON.stringify({ '1': name, '2': clinic, '3': doctor, '4': 'It has been a while since your last visit. Please contact the clinic if you would like to schedule an appointment.' }), _message_body: `Hi ${name}. It has been a while since we last saw you at ${clinic}. Please contact the clinic if you would like to book an appointment with ${doctor}.` } };
});
